const now = new Date();
const prevMonth = new Date(now.getFullYear(), now.getMonth() - 1, 1);
const prevMonthEnd = new Date(now.getFullYear(), now.getMonth(), 0);

return [{ json: {
  date_from: prevMonth.toISOString().split('T')[0],
  date_to: prevMonthEnd.toISOString().split('T')[0],
  month_name: prevMonth.toLocaleDateString('en-US', { month: 'long', year: 'numeric' }),
  current_month: now.toLocaleDateString('en-US', { month: 'long', year: 'numeric' }),
  current_year: now.getFullYear(),
  current_month_num: now.getMonth() + 1
}}];

const invoices = $('Odoo — Get Posted Invoices/Bills').all().map(i => i.json);
const taxLines = $('Odoo — Get Tax Lines').all().map(i => i.json);
const flat_inv = Array.isArray(invoices[0]) ? invoices[0] : invoices;
const flat_tax = Array.isArray(taxLines[0]) ? taxLines[0] : taxLines;
const dates = $('Calculate Date Range').first().json;

// Classify invoices
const sales = flat_inv.filter(i => i.move_type === 'out_invoice' || i.move_type === 'out_refund');
const purchases = flat_inv.filter(i => i.move_type === 'in_invoice' || i.move_type === 'in_refund');

// VAT validation
const issues = [];
let vatTotal = 0;
let ewtTotal = 0;

for (const inv of flat_inv) {
  if (!inv || !inv.id) continue;
  const taxAmt = inv.amount_tax || 0;
  const untaxed = inv.amount_untaxed || 0;

  // Check if VAT is applied (12% standard PH rate)
  if (untaxed > 0 && taxAmt === 0) {
    issues.push({
      type: 'missing_vat',
      severity: 'high',
      invoice: inv.name,
      partner: Array.isArray(inv.partner_id) ? inv.partner_id[1] : inv.partner_id,
      amount: untaxed,
      message: `No tax applied on ${inv.name} (${inv.move_type}) — amount: PHP ${untaxed.toFixed(2)}`
    });
  }

  // Check VAT rate reasonableness (should be ~12% of untaxed)
  if (untaxed > 0 && taxAmt > 0) {
    const effectiveRate = (taxAmt / untaxed) * 100;
    if (effectiveRate < 10 || effectiveRate > 15) {
      issues.push({
        type: 'unusual_tax_rate',
        severity: 'medium',
        invoice: inv.name,
        partner: Array.isArray(inv.partner_id) ? inv.partner_id[1] : inv.partner_id,
        effective_rate: effectiveRate.toFixed(2),
        message: `Unusual tax rate ${effectiveRate.toFixed(2)}% on ${inv.name} (expected ~12% VAT)`
      });
    }
    vatTotal += taxAmt;
  }

  // Check fiscal position for vendor bills (EWT)
  if ((inv.move_type === 'in_invoice' || inv.move_type === 'in_refund') && !inv.fiscal_position_id) {
    issues.push({
      type: 'missing_fiscal_position',
      severity: 'medium',
      invoice: inv.name,
      partner: Array.isArray(inv.partner_id) ? inv.partner_id[1] : inv.partner_id,
      message: `No fiscal position on vendor bill ${inv.name} — EWT may not be applied correctly`
    });
  }
}

// BIR filing deadlines for current month
const month = dates.current_month_num;
const year = dates.current_year;
const deadlines = [
  { form: '2550M', desc: 'Monthly VAT Return', deadline: `${year}-${String(month).padStart(2,'0')}-20`, penalty: 'Surcharge 25% + Interest 12% p.a.' },
  { form: '2550Q', desc: 'Quarterly VAT Return (if quarter-end)', deadline: month % 3 === 1 ? `${year}-${String(month).padStart(2,'0')}-25` : 'N/A', penalty: 'Surcharge 25% + Interest 12% p.a.' },
  { form: '0619E', desc: 'Monthly EWT Remittance', deadline: `${year}-${String(month).padStart(2,'0')}-10`, penalty: 'Surcharge 25% + Interest 12% p.a. + Compromise' },
  { form: '1601C', desc: 'Monthly Withholding Tax on Compensation', deadline: `${year}-${String(month).padStart(2,'0')}-10`, penalty: 'Surcharge 25% + Interest 12% p.a.' },
  { form: '2307', desc: 'Certificate of Creditable Tax Withheld (issue to vendor)', deadline: `${year}-${String(month).padStart(2,'0')}-20`, penalty: 'PHP 1,000 per certificate' }
].filter(d => d.deadline !== 'N/A');

return [{ json: {
  period: dates.month_name,
  current_month: dates.current_month,
  sales_count: sales.filter(s => s.id).length,
  sales_total: sales.reduce((s, i) => s + (i.amount_total || 0), 0),
  purchase_count: purchases.filter(p => p.id).length,
  purchase_total: purchases.reduce((s, i) => s + (i.amount_total || 0), 0),
  vat_collected: vatTotal,
  tax_lines_count: flat_tax.filter(t => t.id).length,
  issues: issues,
  issue_count: issues.length,
  high_severity: issues.filter(i => i.severity === 'high').length,
  deadlines: deadlines,
  invoices_sample: flat_inv.slice(0, 20).map(i => ({
    name: i.name, type: i.move_type,
    partner: Array.isArray(i.partner_id) ? i.partner_id[1] : i.partner_id,
    untaxed: i.amount_untaxed, tax: i.amount_tax, total: i.amount_total,
    fiscal_position: Array.isArray(i.fiscal_position_id) ? i.fiscal_position_id[1] : (i.fiscal_position_id || 'None')
  }))
}}];

const gptResponse = $input.first().json;
const analysis = gptResponse.choices?.[0]?.message?.content || 'No analysis generated';
const data = $('Validate Tax Compliance').first().json;

const today = new Date().toISOString().split('T')[0];
const priority = data.high_severity > 0 ? '1' : '0';

const description = `## Monthly Tax Compliance Report

**Period**: ${data.period}
**Run date**: ${today}
**Company**: TBWA\SMP (CID=2)

### Transaction Summary
| Type | Count | Total (PHP) |
|------|-------|-------------|
| Sales Invoices | ${data.sales_count} | ${data.sales_total.toFixed(2)} |
| Purchase Bills | ${data.purchase_count} | ${data.purchase_total.toFixed(2)} |
| VAT Collected | — | ${data.vat_collected.toFixed(2)} |

### Issues Found: ${data.issue_count}
- High severity: ${data.high_severity}
- Medium severity: ${data.issue_count - data.high_severity}

### BIR Filing Deadlines (${data.current_month})
${data.deadlines.map(d => '- **' + d.form + '**: ' + d.desc + ' — Due: ' + d.deadline).join('
')}

---

${analysis}`;

return [{ json: {
  task_name: `Tax Compliance Report — ${data.period}`,
  description: description,
  project_id: 5,
  user_id: 17,
  priority: priority
}}];
